import{_ as s,o as t,c as n,a0 as e}from"./chunks/framework.CaIcDsGb.js";const u=JSON.parse('{"title":"AI 终端助手的设计哲学","description":"从 iFlow CLI、Claude Code、Hermes Agent 三个终端 AI 助手中提炼通用设计模式与架构思路","frontmatter":{"date":"2026-04-29T00:00:00.000Z","description":"从 iFlow CLI、Claude Code、Hermes Agent 三个终端 AI 助手中提炼通用设计模式与架构思路","tags":["AI","架构设计","工具","设计模式"],"top":1},"headers":[],"relativePath":"ideas/ai-cli-design.md","filePath":"ideas/ai-cli-design.md","lastUpdated":1777443593000}'),o={name:"ideas/ai-cli-design.md"};function l(i,a,p,d,r,h){return t(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="ai-终端助手的设计哲学" tabindex="-1">AI 终端助手的设计哲学 <a class="header-anchor" href="#ai-终端助手的设计哲学" aria-label="Permalink to &quot;AI 终端助手的设计哲学&quot;">​</a></h1><p>过去一年，终端 AI 编程助手领域爆发式增长。iFlow CLI 积累了 5000+ Star 后宣布关停，Claude Code 成为主流选择，Hermes Agent 探索本地化路线。三款工具走了截然不同的路，但它们的架构设计中有一些共通的智慧。</p><p>本文不是使用教程，而是提炼这些工具背后的<strong>设计思路</strong>——哪些决策被证明有效，哪些模式值得在自己的工具和系统设计中复用。</p><hr><h2 id="一、权限分级-信任不是二元的" tabindex="-1">一、权限分级：信任不是二元的 <a class="header-anchor" href="#一、权限分级-信任不是二元的" aria-label="Permalink to &quot;一、权限分级：信任不是二元的&quot;">​</a></h2><h3 id="现状" tabindex="-1">现状 <a class="header-anchor" href="#现状" aria-label="Permalink to &quot;现状&quot;">​</a></h3><p>多数 CLI 工具对权限的处理是&quot;全给&quot;或&quot;全不给&quot;。用户要么 <code>sudo</code> 一把梭，要么束手束脚。</p><h3 id="iflow-cli-的做法" tabindex="-1">iFlow CLI 的做法 <a class="header-anchor" href="#iflow-cli-的做法" aria-label="Permalink to &quot;iFlow CLI 的做法&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yolo 模式      → 最大权限，自动执行所有操作</span></span>
<span class="line"><span>接受编辑模式   → 仅允许文件修改，其他操作需确认</span></span>
<span class="line"><span>计划模式       → 先出计划再执行，关键决策需确认</span></span>
<span class="line"><span>默认模式       → 所有操作均需用户确认</span></span></code></pre></div><p>四种模式对应四种场景：</p><table tabindex="0"><thead><tr><th>模式</th><th>适用场景</th><th>风险</th></tr></thead><tbody><tr><td>yolo</td><td>信任度高的重复任务</td><td>高</td></tr><tr><td>接受编辑</td><td>日常编码、重构</td><td>中</td></tr><tr><td>计划模式</td><td>架构决策、跨文件改动</td><td>低</td></tr><tr><td>默认</td><td>探索性工作</td><td>最低</td></tr></tbody></table><h3 id="claude-code-的做法" tabindex="-1">Claude Code 的做法 <a class="header-anchor" href="#claude-code-的做法" aria-label="Permalink to &quot;Claude Code 的做法&quot;">​</a></h3><p>通过 <code>permissions</code> 配置实现更细粒度的控制：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(git diff *)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(pnpm test)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;defaultMode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;acceptEdits&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>可以精确到具体命令</strong>，而不是笼统的分类。这种&quot;白名单 + 默认模式&quot;的组合比简单的模式切换更安全。</p><h3 id="设计启示" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><blockquote><p>权限设计的关键不是分多少级，而是<strong>粒度可控</strong>。</p></blockquote><p>好的权限系统应该同时支持：</p><ul><li><strong>模式切换</strong>（快速适配不同场景）</li><li><strong>白名单</strong>（对高频安全操作免确认）</li><li><strong>命令级粒度</strong>（不是整类放行，而是精确到参数）</li></ul><hr><h2 id="二、context-window-把压缩变成系统能力" tabindex="-1">二、Context Window：把压缩变成系统能力 <a class="header-anchor" href="#二、context-window-把压缩变成系统能力" aria-label="Permalink to &quot;二、Context Window：把压缩变成系统能力&quot;">​</a></h2><h3 id="关键认知" tabindex="-1">关键认知 <a class="header-anchor" href="#关键认知" aria-label="Permalink to &quot;关键认知&quot;">​</a></h3><p>AI 编程助手的核心瓶颈不是模型能力，而是<strong>上下文窗口</strong>。一次复杂任务可能涉及几十个文件，数千行代码，远超窗口上限。</p><h3 id="iflow-cli-的做法-1" tabindex="-1">iFlow CLI 的做法 <a class="header-anchor" href="#iflow-cli-的做法-1" aria-label="Permalink to &quot;iFlow CLI 的做法&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当上下文达到 70% 时触发自动压缩</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>提取关键信息（任务目标、已完成步骤、当前状态）</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>压缩为摘要，释放空间</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>继续执行</span></span></code></pre></div><p>这个机制让它在只有 128K 窗口的情况下也能完成跨文件的复杂任务。</p><h3 id="claude-code-的做法-1" tabindex="-1">Claude Code 的做法 <a class="header-anchor" href="#claude-code-的做法-1" aria-label="Permalink to &quot;Claude Code 的做法&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>压缩引擎 + 关键信息保护</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>压缩阈值可配（threshold: 0.5, target_ratio: 0.2）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>保护最近 N 轮对话不被压缩（protect_last_n: 20）</span></span></code></pre></div><p>关键设计细节：<strong>不压缩最近的对话</strong>。因为最近几轮包含当前任务的核心上下文，压缩它们等于让 AI 失忆。</p><p>同时通过 <strong>TodoWrite</strong> 工具让 AI 主动记录进度——即使上下文被压缩，任务进度也不会丢失。</p><h3 id="设计启示-1" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示-1" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><blockquote><p>上下文压缩的核心不是&quot;存更多&quot;，而是<strong>知道什么该忘、什么该留</strong>。</p></blockquote><p>一个好的压缩策略至少考虑：</p><ol><li><strong>时序权重</strong> — 越近的内容越重要</li><li><strong>任务锚点</strong> — 当前目标不能丢</li><li><strong>结构化进度</strong> — 用 TodoWrite 等机制在压缩前固化状态</li></ol><hr><h2 id="三、工具生态-开放市场-vs-内置全家桶" tabindex="-1">三、工具生态：开放市场 vs 内置全家桶 <a class="header-anchor" href="#三、工具生态-开放市场-vs-内置全家桶" aria-label="Permalink to &quot;三、工具生态：开放市场 vs 内置全家桶&quot;">​</a></h2><h3 id="三种路线" tabindex="-1">三种路线 <a class="header-anchor" href="#三种路线" aria-label="Permalink to &quot;三种路线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>策略</th><th>表现</th></tr></thead><tbody><tr><td>iFlow CLI</td><td>开放市场 + MCP</td><td>一键安装 SubAgent、MCP、自定义指令</td></tr><tr><td>Claude Code</td><td>Agent + Skill + MCP</td><td>内置丰富的 Agent 类型，Skill 可扩展</td></tr><tr><td>Hermes Agent</td><td>内置全家桶</td><td>29 个工具全部自带，无需外部安装</td></tr></tbody></table><h3 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h3><p><strong>开放市场（iFlow CLI）</strong> 的思路最贴近 App Store——降低扩展门槛，让生态自己生长。问题在于需要足够大的社区才能形成正循环。</p><p><strong>Agent + Skill（Claude Code）</strong> 的思路更务实——内置高质量的基础能力（planner、code-reviewer、tdd-guide），同时通过 MCP 和 Skill 体系保持可扩展性。这避免了开放市场&quot;质量参差不齐&quot;的问题。</p><p><strong>内置全家桶（Hermes Agent）</strong> 适合个人定制场景——所有工具自己掌控，不依赖任何外部服务。缺点是维护成本全部自己承担。</p><h3 id="设计启示-2" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示-2" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><blockquote><p><strong>分层扩展</strong>是更好的模式：核心能力内置保证质量底线，扩展接口（MCP/Skill）保证灵活性。</p></blockquote><p>理想的架构应该是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  自定义 Skill / MCP      │  ← 用户自由扩展</span></span>
<span class="line"><span>├─────────────────────────┤</span></span>
<span class="line"><span>│  官方 Skill 库           │  ← 社区贡献 + 审核</span></span>
<span class="line"><span>├─────────────────────────┤</span></span>
<span class="line"><span>│  内置 Agent（plan/cr/tdd）│  ← 开箱即用</span></span>
<span class="line"><span>├─────────────────────────┤</span></span>
<span class="line"><span>│  CLI 核心（tools/session）│  ← 不可变基础</span></span>
<span class="line"><span>└─────────────────────────┘</span></span></code></pre></div><hr><h2 id="四、人机交互-性格化-vs-工具化" tabindex="-1">四、人机交互：性格化 vs 工具化 <a class="header-anchor" href="#四、人机交互-性格化-vs-工具化" aria-label="Permalink to &quot;四、人机交互：性格化 vs 工具化&quot;">​</a></h2><h3 id="有趣的发现" tabindex="-1">有趣的发现 <a class="header-anchor" href="#有趣的发现" aria-label="Permalink to &quot;有趣的发现&quot;">​</a></h3><p>Hermes Agent 内置了 <strong>12 种人格</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>helpful    → 友好助手</span></span>
<span class="line"><span>technical  → 技术专家</span></span>
<span class="line"><span>concise    → 简短精炼</span></span>
<span class="line"><span>kawaii     → 可爱卖萌</span></span>
<span class="line"><span>catgirl    → 猫娘风格</span></span>
<span class="line"><span>pirate     → 海盗风格</span></span>
<span class="line"><span>noir       → 黑色电影风</span></span>
<span class="line"><span>shakespeare → 莎士比亚风</span></span></code></pre></div><p>这不是噱头。不同的任务场景需要不同的交互风格：</p><ul><li><strong>生产环境排错</strong> → 需要 <code>concise</code>，一个多余的字都不要</li><li><strong>学习新技术</strong> → 需要 <code>teacher</code>，耐心解释</li><li><strong>长时间的重复工作</strong> → 需要一点个性，缓解疲劳</li><li><strong>正式报告</strong> → 需要 <code>technical</code>，保持专业</li></ul><h3 id="claude-code-的做法-2" tabindex="-1">Claude Code 的做法 <a class="header-anchor" href="#claude-code-的做法-2" aria-label="Permalink to &quot;Claude Code 的做法&quot;">​</a></h3><p>通过 System Prompt 中的 <code>language</code>、规则文件、AGENTS.md 来影响交互风格，但不支持运行时切换。</p><h3 id="设计启示-3" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示-3" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><blockquote><p>AI 助手的交互风格应该和<strong>工作场景</strong>匹配，而不是一成不变。</p></blockquote><p>好的设计应该允许用户在<strong>任务级别</strong>切换交互模式，就像 IDE 可以按文件类型切换配色方案一样。</p><hr><h2 id="五、hook-系统-把-每次都要做的事-自动化" tabindex="-1">五、Hook 系统：把&quot;每次都要做的事&quot;自动化 <a class="header-anchor" href="#五、hook-系统-把-每次都要做的事-自动化" aria-label="Permalink to &quot;五、Hook 系统：把&quot;每次都要做的事&quot;自动化&quot;">​</a></h2><h3 id="三层-hook-模型" tabindex="-1">三层 Hook 模型 <a class="header-anchor" href="#三层-hook-模型" aria-label="Permalink to &quot;三层 Hook 模型&quot;">​</a></h3><p>Claude Code 的 Hook 体系是最成熟的参考：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PreToolUse  → 工具调用前（拦截、校验、提醒）</span></span>
<span class="line"><span>PostToolUse → 工具调用后（格式化、状态更新、日志）</span></span>
<span class="line"><span>Stop        → 会话结束时（清理、格式化、提测）</span></span></code></pre></div><h3 id="实际应用价值" tabindex="-1">实际应用价值 <a class="header-anchor" href="#实际应用价值" aria-label="Permalink to &quot;实际应用价值&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Hook 时机</th><th>实际用途</th></tr></thead><tbody><tr><td><code>PreToolUse</code></td><td>拦截 <code>npm run dev</code> 在裸终端执行，强制进 tmux</td></tr><tr><td><code>PreToolUse</code></td><td>检测到 <code>rm -rf</code> 时二次确认</td></tr><tr><td><code>PostToolUse</code></td><td>每次编辑后自动 <code>git status</code></td></tr><tr><td><code>PostToolUse</code></td><td>每次编辑后自动格式化</td></tr><tr><td><code>Stop</code></td><td>会话结束前检查 <code>console.log</code> 残留</td></tr></tbody></table><h3 id="设计启示-4" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示-4" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><blockquote><p>Hook 的本质是<strong>把团队规范编码为自动化检查</strong>，而不是靠人记。</p></blockquote><p>一个好的 Hook 系统应该：</p><ol><li><strong>支持正则匹配</strong>（精确拦截特定命令）</li><li><strong>支持链式执行</strong>（一个触发可以跑多个检查）</li><li><strong>fail-open vs fail-close 可选</strong>（安全检查 fail-close，提示类 fail-open）</li></ol><hr><h2 id="六、会话管理-状态不该丢了" tabindex="-1">六、会话管理：状态不该丢了 <a class="header-anchor" href="#六、会话管理-状态不该丢了" aria-label="Permalink to &quot;六、会话管理：状态不该丢了&quot;">​</a></h2><h3 id="iflow-cli-的独特设计" tabindex="-1">iFlow CLI 的独特设计 <a class="header-anchor" href="#iflow-cli-的独特设计" aria-label="Permalink to &quot;iFlow CLI 的独特设计&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--resume 恢复上次会话</span></span>
<span class="line"><span>/chat 查看历史对话</span></span></code></pre></div><p>它把&quot;恢复上下文&quot;做成了核心流程的一环。断网、关终端、换机器都不会丢失进度。</p><h3 id="claude-code-的做法-3" tabindex="-1">Claude Code 的做法 <a class="header-anchor" href="#claude-code-的做法-3" aria-label="Permalink to &quot;Claude Code 的做法&quot;">​</a></h3><p>通过 Memory 系统持久化用户偏好、项目上下文，但会话本身不跨进程。</p><h3 id="设计启示-5" tabindex="-1">设计启示 <a class="header-anchor" href="#设计启示-5" aria-label="Permalink to &quot;设计启示&quot;">​</a></h3><p>将 <strong>Memory（长期记忆）</strong> 和 <strong>Session（短期会话）</strong> 分开管理：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Memory（持久化，跨会话）</span></span>
<span class="line"><span>├── 用户偏好、角色信息</span></span>
<span class="line"><span>├── 项目背景、架构决策</span></span>
<span class="line"><span>└── 反馈历史（什么做法有效）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session（临时，单次会话）</span></span>
<span class="line"><span>├── 当前任务上下文</span></span>
<span class="line"><span>├── Todo 进度</span></span>
<span class="line"><span>└── 中间产物</span></span></code></pre></div><p>关停并不可怕，可怕的是好的思路没被记录下来。iFlow CLI 虽然关了，但它的权限分级、自动压缩、开放市场这些设计思路，值得沉淀到下一批工具中去。</p><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设计领域</th><th>核心原则</th></tr></thead><tbody><tr><td>权限</td><td>模式切换 + 白名单 + 命令级粒度</td></tr><tr><td>上下文</td><td>时序权重 + 任务锚点 + 结构化进度</td></tr><tr><td>生态</td><td>分层扩展：核心内置 → 官方库 → 自定义</td></tr><tr><td>交互</td><td>按场景匹配风格，不是固定人格</td></tr><tr><td>自动化</td><td>Hook 把规范编码为检查，不是靠人记</td></tr><tr><td>状态</td><td>Memory 长期 + Session 短期，分而治之</td></tr></tbody></table><p>这些模式不仅在 AI 终端工具中成立，在做任何需要&quot;人机协作&quot;的系统时都站得住脚。</p>`,84)])])}const g=s(o,[["render",l]]);export{u as __pageData,g as default};
